"""
MKT Original — Luke chapters 2–3
Output: data/commentary/mkt-original/luke.json
Run: python3 scripts/zc-original-luke-2-3.py

Key linguistic nodes: eudokias (gen.) at 2:14 — the crucial peace-to-those-of-his-
favor reading vs. eudokia (nom.); sunterousa/sunballousa at 2:19 — pondering as
comparing; dei me einai en tois tou patros mou at 2:49 — the Father's house/affairs
ambiguity; baptisma metanoias / puri at 3:3-16; the Lukan genealogy to Adam (3:38).
Chs 2:11 and 2:29 and 3:22 already present — merge_comm skips them.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    # INTENT: Merge new verse entries without overwriting already-present keys.
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

LUKE_CH2_3 = {
  "2": {
    "1": '<p><strong>apographesthai pasan ten oikoumenen</strong> — to register all the inhabited world — <em>apographē</em> (enrollment, registration) is an administrative census for taxation; <em>oikoumenē</em> (the inhabited world) is Luke\'s preferred term for the Roman empire. The dating reference to Quirinius (<em>hēgemoneuontos</em>) is the most discussed chronological problem in Luke — Josephus places the Quirinius census in 6-7 CE, not at Jesus\'s birth. Various solutions include a prior legateship or an earlier enrollment; the historical tension does not affect the theological point Luke is making: the Roman empire\'s administrative machinery becomes the instrument of the Davidic birthplace prophecy.</p>',
    "2": '<p><strong>hautē apographē prōtē egeneto</strong> — this registration was the first — the phrase <em>prōtē egeneto</em> may be translated "first took place" (superlative) or "was before" (comparative), which some read as "this registration was before the one Quirinius made [as governor]." The syntactical ambiguity has been the source of extensive debate. Luke\'s purpose is the historical anchoring characteristic of his prologue method (1:1-4): he is demonstrating that the birth of Christ occurred within datable human history.</p>',
    "3": '<p><strong>eporeuonto pantes apographesthai</strong> — all went to be registered — the imperfect <em>eporeuonto</em> (were going, were traveling) depicts the ongoing movement of population. The mass registration is the historical mechanism through which the Davidic birthplace requirement is met; Luke presents the Roman political order as an unwitting instrument of divine providence without labeling it as such.</p>',
    "4": '<p><strong>anebē de kai Iōsēph apo tēs Galilaias ek poleōs Nazareth</strong> — Joseph also went up from Galilee, from Nazareth — <em>anebainō</em> (go up) is the standard verb for travel to Jerusalem/Judea, as higher elevation; the journey is the fulfillment of the Davidic-birthplace requirement. <em>Polin Dauid</em> (city of David) is Bethlehem, not Jerusalem — Luke is precise about which city of David is intended.</p>',
    "5": '<p><strong>engkuō ousē</strong> — who was pregnant — <em>engkuos</em> (pregnant, great with child) is a medical term, consistent with Luke\'s medical vocabulary (noted by Hobart). The reference to Mary as Joseph\'s <em>memnesteumenē</em> (promised in marriage, betrothed) at this point of pregnancy maintains the earlier annunciation narrative\'s implication without requiring an explanation Luke has already provided.</p>',
    "6": '<p><strong>eplēsthēsan hai hēmerai tou tekein autēn</strong> — the days for her to give birth were fulfilled — <em>eplēsthēsan</em> (were fulfilled, were completed) is Luke\'s fulfillment language; the same verb appears throughout Luke-Acts when divine plans reach completion. <em>Tekein</em> (to give birth, infinitive of <em>tiktō</em>) is the verb of the annunciation (1:31); the verb link connects the promise to the fulfillment.</p>',
    "7": '<p><strong>ton huion autēs ton prōtotokon</strong> — her firstborn son — <em>prōtotokos</em> (firstborn) has both legal and theological weight: the firstborn son receives the covenant inheritance and consecration to God (Exod 13:2; Num 18:15-16). The term does not say anything about whether Mary had later children — that is determined by other texts. <strong>espargānōsen</strong> — she wrapped him in swaddling cloths — <em>sparganoa</em> are strips of cloth for swaddling infants (a standard Greek medical term); Luke\'s use of the term is both precise and symbolic. <strong>phatnē</strong> — manger — the manger is the sign in v.12; the word means an animal feeding trough, not necessarily a stable (kataluma = lodging place, not necessarily an inn).</p>',
    "8": '<p><strong>poimenes</strong> — shepherds — the choice of shepherds as the first recipients of the angelic announcement is significant against the background that shepherds in Second Temple Palestine were often considered ritually unreliable (unable to testify in court, frequently in contact with what was considered unclean). Luke presents the announcement going first to those society marginalized. <strong>agraulountes</strong> — living in the fields — compound of <em>agros</em> (field) + <em>aulē</em> (courtyard, dwelling); they sleep in the open field rather than in shelter.</p>',
    "9": '<p><strong>angelos kyriou epestē autois</strong> — an angel of the Lord appeared to them — <em>ephistēmi</em> (stand upon, appear suddenly) is Luke\'s preferred verb for angelic appearance (cf. 1:11; Acts 12:7; 23:11); it conveys sudden presence rather than gradual approach. <strong>doxa kyriou</strong> — the glory of the Lord — <em>doxa</em> here is the Shekinah-light of divine presence; the same luminous manifestation that marked the tabernacle and temple. The shepherds\' fear is the standard response to holy divine presence.</p>',
    "10": '<p><strong>euangelizomai hymin charan megalēn</strong> — I bring you good news of great joy — <em>euangelizomai</em> is Luke\'s distinctive verb (used 10 times in Luke, 15 in Acts, rare elsewhere in the Gospels); it is the proclamation-verb of Isa 61:1 (the Servant announcing good news). The dative <em>hymin</em> (to you — the shepherds, present) followed by <em>panti tō laō</em> (for all the people, future/broader) traces the scope: the announcement begins with the marginalized few and extends to all Israel.</p>',
    "11": '<p><strong>soter hos estin Christos Kyrios</strong> — a Savior who is Christ the Lord — the angelic birth announcement stacks three titles on the newborn: <em>soter</em> (savior — the most frequent soteriology term in Luke-Acts), <em>Christos</em> (Messiah/Anointed One), and <em>Kyrios</em> (Lord — the LXX title for YHWH). The combination is unprecedented and theologically dense; no other NT birth announcement stacks all three. <strong>sēmeron</strong> — today — the eschatological now-ness of salvation in Luke (cf. 4:21; 19:9; 23:43).</p>',
    "12": '<p><strong>kai touto hymin to sēmeion</strong> — and this will be the sign for you — the <em>sēmeion</em> (sign) is striking: not a miraculous portent but a baby in a manger. The sign is the incarnation itself — the lowliness of the setting confirms, rather than contradicts, that this is the messianic Savior. The <em>phatin</em> (manger) as sign echoes the Isaianic servant-sign of the child: the expected messianic triumph comes in unexpected lowliness.</p>',
    "13": '<p><strong>stratias ouraniou</strong> — a heavenly army/host — <em>stratia</em> is the military term (army, host); the genitive <em>ouraniou</em> (heavenly) qualifies the army\'s origin. The heavenly host both worships (as the angels of God) and stands ready for battle — the dual meaning of the divine army. The praise they offer (v.14) transforms the military assembly into a liturgical choir, though the military connotation remains: the hosts of heaven declare the peace that Christ\'s coming brings.</p>',
    "14": '<p><strong>en anthrōpois eudokias</strong> — among people of his good pleasure/favor — the genitive <em>eudokias</em> (of good will, of favor) is the crucial textual and theological crux. The earliest and best manuscripts (p75, B, Sinaiticus, A) read <em>eudokias</em> (genitive), making the phrase "peace to people of his good will/favor" — those whom God favors, the recipients of his gracious election. A later reading, <em>eudokia</em> (nominative), yields "peace on earth, good will to men" — making good will the third coordinate gift. The genitive is almost certainly original (lectio difficilior; reflected in Jerome\'s "bonae voluntatis") and is theologically richer: the peace announced is not universal but directed to those within the sphere of divine grace. The Qumran texts similarly use "men of his good pleasure" (<em>bnei rezono</em>) as a technical term for the covenant community.</p>',
    "15": '<p><strong>hōs apēlthon ap autōn</strong> — when they had gone from them — the aorist genitive absolute <em>apelthontōn</em> (having departed) is a clean narrative transition. The shepherds\' immediate response <em>dielthoumen</em> (let us go through — first person plural aorist subjunctive hortatory) signals communal decision and action. <em>Rēma</em> (word, thing) at the end — "this thing that has happened" — uses the theologically loaded word for divine speech/deed throughout Luke-Acts.</p>',
    "16": '<p><strong>aneuron te tēn Mariam</strong> — they found Mary — <em>aneuriskō</em> (find by searching) is a compound form of <em>heuriskō</em> that emphasizes the searching process; they located what they sought by inquiry. <em>Spoudē</em> (haste) in v.16 describes their movement — not reckless urgency but eager intentionality. The discovery confirms the sign: the baby in the manger is exactly as the angel said.</p>',
    "17": '<p><strong>egnōrisan peri tou rēmatos</strong> — they made known the word — <em>gnōrizō</em> (make known, reveal) is used for the public proclamation of what was privately received; the shepherds become the first evangelists, announcing to others what the angel announced to them. The pattern — receive, go, make known — is the basic missionary structure that Luke will develop throughout Acts.</p>',
    "18": '<p><strong>pantes hoi akousantes</strong> — all who heard — Luke emphasizes the crowd\'s amazed response (<em>ethaumasan</em> — they were amazed, marveled) as the standard human response to the divine breaking into ordinary life. The imperfect <em>ethaumasan</em> (were marveling) suggests ongoing astonishment, not a momentary reaction. The amazement does not necessarily indicate faith; it is the raw material from which faith can grow.</p>',
    "19": '<p><strong>hē de Mariam panta sunētērei ta rēmata tauta sunballousa en tē kardia autēs</strong> — Mary kept all these things and pondered them in her heart — two participles describe Mary\'s interior response. <em>Suntēreō</em> (keep together, treasure up) suggests active preservation of memory; it appears in Dan 7:28 LXX for Daniel preserving the vision in his heart. <em>Sunballousa</em> (pondering, throwing together) from <em>sunballō</em> (to throw together, compare) suggests the active work of interpretation — Mary is comparing, correlating, and seeking to understand the meaning of what is happening. This verse establishes Mary as the contemplative witness whose perspective shapes Luke\'s infancy narrative.</p>',
    "20": '<p><strong>hupestrepsan hoi poimenes</strong> — the shepherds returned — <em>hupostrephō</em> (return) is one of Luke\'s most frequent verbs (32 times in Luke-Acts vs. 3 in Matthew-Mark-John). The return with praise and glory to God is the standard Lukan conclusion to a healing/salvation event: the recipients of grace return to their lives glorifying God. <em>Doxazontes kai ainountes</em> (glorifying and praising) are the paired verbs of worship throughout Luke-Acts.</p>',
    "21": '<p><strong>hote eplēsthēsan hēmerai oktō tou peritemein auton</strong> — when eight days were fulfilled for circumcising him — <em>eplēsthēsan</em> (were fulfilled) is Luke\'s covenant-completion language; the eighth day circumcision is the Abrahamic covenant sign (Gen 17:12; Lev 12:3). <em>Peritemein</em> (to circumcise, infinitive of <em>peritemnō</em>) places Jesus within the covenant community from infancy. The name Iēsous is given at circumcision as the angel commanded (1:31) — the name and covenant sign are received together.</p>',
    "22": '<p><strong>hote eplēsthēsan hai hēmerai tou katharismou autōn kata ton nomon Mōuseōs</strong> — when the days of their purification according to the law of Moses were completed — the <em>katharismos</em> (purification) follows Lev 12:1-8: 40 days after the birth of a son, the mother undergoes a purification rite at the temple. The pronoun <em>autōn</em> (their) is unusual — purification was the mother\'s rite, not both parents\'; some suggest Luke is assimilating the purification to a presentation. <em>Anagagein</em> (to bring up, present) is the presentation vocabulary.</p>',
    "23": '<p><strong>kathōs gegraptai en nomō kyriou</strong> — as it is written in the law of the Lord — the citation follows Exod 13:2, 12 (every firstborn male is holy to the Lord). Luke uses <em>prōtotokon</em> (firstborn) to connect this verse to v.7; the consecration of the firstborn in the law is the legal context for Jesus\'s presentation. <em>Hagion tō kyriō klēthēsetai</em> (he will be called holy to the Lord) echoes the annunciation language (1:35, <em>hagion klēthēsetai</em>).</p>',
    "24": '<p><strong>zeugos trugonōn ē duo nossous peristerōn</strong> — a pair of turtledoves or two young pigeons — the offering is the poor woman\'s alternative prescribed in Lev 12:8 (when she cannot afford a lamb). Luke\'s inclusion of this detail establishes the family\'s economic status — they are among the <em>anawim</em>, the humble poor of Israel — and foreshadows the Magnificat\'s theme (the humble lifted up). The use of <em>zeugos</em> (yoke, pair) for the birds is precise.</p>',
    "25": '<p><strong>paraklēsin tou Israēl</strong> — the consolation of Israel — <em>paraklēsis</em> is one of Luke\'s theologically loaded terms: consolation, comfort, encouragement. It echoes Isa 40:1 (the opening of Deutero-Isaiah: "Comfort, comfort my people") — the messianic expectation that God would return to comfort his exiled, suffering people. Simeon\'s hope is the hope of Isa 40-66 in a single word. <strong>pneuma hagion ēn ep auton</strong> — the Holy Spirit was upon him — the threefold Spirit-reference in vv.25-27 (upon him, revealed to him, moved by him) structures the Nunc Dimittis scene as a pneumatic event.</p>',
    "26": '<p><strong>kechrēmatismenon hypo tou pneumatos tou hagiou</strong> — divinely revealed/warned by the Holy Spirit — <em>chrēmatizō</em> is the technical term for receiving a divine oracle or divine instruction (used for the Magi\'s warning in Matt 2:12; for Noah in Heb 11:7); it conveys authoritative divine communication. The content of the revelation — <em>mē idein thanaton prin an idē ton Christon kyriou</em> (he would not see death before seeing the Lord\'s Christ) — ties Simeon\'s hope to the specific messianic moment.</p>',
    "27": '<p><strong>en tō pneumati</strong> — in/by the Spirit — the preposition <em>en</em> with <em>pneumati</em> can be instrumental (by the Spirit) or locative (in the sphere of the Spirit); the ambiguity is typically Lukan. Simeon\'s Spirit-directed movement to the temple and the parents\' bringing of Jesus at the same moment is presented as providential coordination — both parties are following separate promptings that converge in the temple.</p>',
    "28": '<p><strong>edexato auto eis tas agklas autou</strong> — he took him up in his arms — <em>agkale</em> (arm, elbow) is the word for the bent arm that cradles a child; the physical gesture of reception is the enacted reception of the Messiah by old Israel. Simeon holding the infant Jesus is the visual image that the Nunc Dimittis makes verbal: he has received the salvation his nation waited for.</p>',
    "29": '<p><strong>despota</strong> — Sovereign Master — the address <em>despota</em> (absolute master, sovereign) rather than the more common <em>kyrie</em> signals the servant\'s relationship to the absolutely sovereign Lord; <em>despotēs</em> implies total ownership. <strong>kata to rēma sou</strong> — according to your word — the word/promise that Simeon received in v.26 is now being fulfilled; the Nunc Dimittis is a word-fulfillment acknowledgment. <strong>en eirēnē</strong> — in peace — the peace of v.14 (the angels\' announcement) is now personally received by the one who has seen the Lord\'s salvation.</p>',
    "30": '<p><strong>hoti eidon hoi ophthalmoi mou to sōtērion sou</strong> — for my eyes have seen your salvation — <em>sōtērion</em> (salvation as a noun/neuter) is Luke\'s preferred form (also 3:6; Acts 28:28); the phrase echoes Ps 98:2-3 LXX (<em>eidon panta ta perata tēs gēs to sōtērion tou theou hēmōn</em>). The salvation that is seen by the eyes is the infant — salvation is personified in Christ, not merely a concept.</p>',
    "31": '<p><strong>ho hetoimasas kata prosōpon pantōn tōn laōn</strong> — which you have prepared in the presence of all peoples — <em>hetoimazō</em> (prepare) echoes Mal 3:1 and the Baptist\'s preparation language; YHWH has prepared the salvation in advance. <em>Kata prosōpon pantōn tōn laōn</em> (in the face/presence of all peoples) — the salvation is public, not private or esoteric.</p>',
    "32": '<p><strong>phōs eis apokalupsin ethnōn</strong> — a light for revelation to the Gentiles — <em>apokalupsis</em> (unveiling, revelation) combined with <em>phōs</em> (light) draws on Isa 42:6 and 49:6 (the Servant as light to the nations). <em>Ethnōn</em> (Gentiles/nations) is the first explicit mention of Gentile inclusion in Luke\'s birth narrative — the scope of salvation transcends Israel. <strong>doxan laou sou Israēl</strong> — the glory of your people Israel — the salvation is for Israel\'s glory as well; the Gentile inclusion does not displace Israel\'s priority but extends the benefit.</p>',
    "33": '<p><strong>kai ēn ho patēr autou kai hē mētēr thaumazontes</strong> — his father and mother were amazed — Luke uses <em>ho patēr autou</em> (his father) for Joseph without theological embarrassment, consistent with the legal/social reality that Joseph is Jesus\'s father in every sense except biological generation. The amazement (<em>thaumazō</em>) at Simeon\'s words about Jesus is the same response as the shepherds\' audience (v.18) — the appropriate human response to the unexpected scope of the divine plan.</p>',
    "34": '<p><strong>keimai eis ptōsin kai anastasin pollōn en tō Israēl</strong> — set for the fall and rising of many in Israel — <em>ptōsis</em> (fall) and <em>anastasis</em> (rising) are the two responses Jesus will produce in Israel; the same Greek word <em>anastasis</em> is used for both the resurrection and the "rising" here. <strong>sēmeion antilegomenon</strong> — a sign that is spoken against/contradicted — <em>antilegō</em> (speak against, contradict) anticipates the opposition that will define Jesus\'s ministry and lead to the cross. The sign that was the silent baby in the manger will become the controversial rabbi and the executed Messiah.</p>',
    "35": '<p><strong>rhomphaia</strong> — a sword — the <em>rhomphaia</em> is the large, curved Thracian sword (as opposed to the shorter <em>machaira</em>); used in LXX for the sword that drove Adam from Eden (Gen 3:24), and the sword of divine judgment throughout the prophets. The sword that will pierce Mary\'s soul is the sword of grief at the cross — but also, perhaps, the sword of the word itself (Heb 4:12). <strong>hopōs an apokalupphthōsin ek pollōn kardiōn dialogismoi</strong> — so that thoughts from many hearts will be revealed — <em>dialogismos</em> (reasoning, internal debate) is consistently negative in Luke; the revealing of hearts is the effect of encountering Christ.</p>',
    "36": '<p><strong>prophetis Hanna</strong> — a prophetess, Anna — <em>prophētis</em> (prophetess, feminine form) is the technical term for one who speaks under divine inspiration; Anna is one of the few NT women explicitly named prophets. The genealogical specificity (<em>thugatēr Phanouel ek phylēs Asēr</em> — daughter of Phanuel, of the tribe of Asher) is unusual for a woman, suggesting her public significance. The note about her age is textually complex: she had lived with her husband seven years, then was a widow of/for 84 years — placing her age at approximately 105 if widowed at 14, or the 84 years may describe the period of her widowhood as the total.</p>',
    "37": '<p><strong>nēsteiais kai deēsesin latreuousa nykta kai hēmeran</strong> — worshiping with fasting and prayer night and day — <em>latreuō</em> (worship, serve with religious devotion) is the liturgical service term; Anna\'s fasting and prayer is continuous, structured worship, not occasional piety. The night-and-day formula (nykta kai hēmeran) emphasizes the comprehensive, uninterrupted nature of her devotion — the posture of one wholly consecrated to anticipating the messianic redemption.</p>',
    "38": '<p><strong>lytrōsin Ierousalēm</strong> — the redemption of Jerusalem — <em>lytrōsis</em> (redemption, ransom-release) echoes <em>lytron</em> (ransom) and the LXX release terminology; it is the technical term for the covenant redemption of God\'s people (Ps 111:9 LXX). The phrase "redemption of Jerusalem" situates Anna\'s hope in the nationalprophetic expectation (Isa 52:9 — "for the LORD has redeemed Jerusalem") that the city\'s exile condition would end with the Messiah\'s coming.</p>',
    "39": '<p><strong>hōs etelesan panta ta kata ton nomon kyriou</strong> — when they had performed all things according to the law of the Lord — Luke\'s <em>telos</em>-language (<em>teleoō</em> = complete, fulfill) here describes legal compliance rather than prophetic fulfillment, but the vocabulary overlap is deliberate. The family\'s complete Torah observance at the birth establishes Jesus\'s continuity with the covenant community even as his identity transcends it.</p>',
    "40": '<p><strong>to de paidion ēuxanen kai ekrataiouto plēroumenon sophia</strong> — the child grew and became strong, filled with wisdom — <em>auxanō</em> (grow) and <em>krataioomai</em> (become strong) are Luke\'s standard developmental verbs (also 1:80 for John); both are imperfects, indicating gradual progress over time. <strong>plēroumenon sophia</strong> — filled with wisdom — <em>plēroō</em> (fill, fulfill) with <em>sophia</em> (wisdom) describes the progressive increase of wisdom in the growing child; the divine wisdom fills him as he grows into his human capacities. <em>Charis theou ēn ep auton</em> — the grace of God was upon him — the same formula as Elizabeth\'s womb-grace for John (1:66); divine favor rests on the child continuously.</p>',
    "41": '<p><strong>kai eporeuonto hoi goneis autou kat etos eis Ierousalem</strong> — his parents went to Jerusalem every year — <em>kata etos</em> (year by year, annually) describes the established practice of Passover pilgrimage. The Deuteronomic law required three annual festivals (Deut 16:16) but Passover was the primary requirement observed by devout families. Luke\'s specification of the parents\' annual practice establishes the piety context for the temple episode and shows that Jesus grew up within regular Passover observance.</p>',
    "42": '<p><strong>hote egeneto etōn dōdeka</strong> — when he was twelve years old — the age of 12 is significant in Jewish practice as approaching bar mitzvah responsibility (technically 13 in rabbinic tradition, but the approach to legal adulthood began earlier). Luke specifies this age because it marks the threshold of religious majority at which a boy begins to take personal responsibility for Torah observance. This is Jesus\'s first appearance as a speaking actor in the narrative.</p>',
    "43": '<p><strong>hupestreyen ho pais Iēsous en Ierousalēm</strong> — the boy Jesus remained in Jerusalem — <em>hypomenō</em> (remain behind, stay) rather than <em>hupostrephō</em> (return) signals that Jesus did not return with the caravan; he stayed deliberately. <em>Hoi goneis autou ouk egnōsan</em> (his parents did not know) — the unknown is their <em>not knowing</em> that he stayed, not a mistake on Jesus\'s part. They assumed he was in the <em>synōdia</em> (traveling company, caravan) — the large group of Galilean pilgrims traveling together.</p>',
    "44": '<p><strong>nomisantes de auton einai en tē synōdia</strong> — supposing him to be in the group — <em>synōdia</em> (company, caravan, traveling group) is a hapax in the NT; the compound (<em>syn</em> = with + <em>hodos</em> = road, journey) describes the pilgrimage group. The assumption that Jesus was somewhere in the group is reasonable — in large caravan travel, extended family and acquaintances would spread across the group. A day\'s journey would have carried them well away from Jerusalem before the absence was noticed.</p>',
    "45": '<p><strong>anastraphentes de anezētoun auton</strong> — when they did not find him, they returned, searching — <em>anazēteō</em> (search for, seek up and down) is an intensive compound of <em>zēteō</em> (seek); the <em>ana-</em> prefix suggests thorough searching in every direction. The three days of searching (one day traveling, one returning, one day in Jerusalem) before finding him in the temple is Luke\'s only narrative that places Jesus in a human learning environment.</p>',
    "46": '<p><strong>en tō hierō kathezomenon en mesō tōn didaskalōn</strong> — sitting in the temple among the teachers — <em>didaskālos</em> (teacher, doctor of the law) in the plural indicates the professional scribal teachers who taught in the temple courts. <em>Kathezomenon en mesō</em> (sitting in the middle) is the posture of a student participating in instruction — sitting on the floor among the teachers (who sat on chairs or benches, the elevated teaching position). The teachers are asking questions and he is answering; but the direction of inquiry suggests that both parties are engaged in the Socratic dialogue of Jewish learning.</p>',
    "47": '<p><strong>existanto de pantes hoi akouontes autou epi tē sunēsei kai tais apokrisesin autou</strong> — all who heard him were astonished at his understanding and his answers — <em>existēmi</em> (stand outside, be astonished — from which we get <em>ekstasis</em>) describes the teachers\' reaction to his answers. <em>Sunesis</em> (understanding, comprehension) is the cognitive intelligence; <em>apokrisis</em> (answer, response) is the verbal expression. The astonishment of the professional teachers is not patronizing (smart child!) but genuine recognition of exceptional insight.</p>',
    "48": '<p><strong>odunōmenoi</strong> — anguished — the word is one of Luke\'s strongest emotional terms (used for the rich man\'s anguish in Hades at 16:24-25; for Paul\'s associates\'s grief at Acts 20:38). Mary\'s report uses the parental first-person dual — <em>ho patēr sou kagō</em> (your father and I) — with Joseph named as father; Luke does not soften the parental perspective to exclude Joseph.</p>',
    "49": '<p><strong>dei me einai en tois tou patros mou</strong> — I must be in my Father\'s things/house — the crucial phrase is <em>tois tou patros mou</em> (the things/house of my Father). The Greek phrase is deliberately ambiguous: <em>ta tou patros</em> can mean "my Father\'s house" (oikos being understood), "my Father\'s affairs/business," or "the things that belong to my Father." Early translations diverged: the Vulgate has <em>in his quae Patris mei sunt</em> (in the things that are my Father\'s); English versions split between "house" and "business/affairs." The ambiguity is productive — in the temple he is in his Father\'s house AND doing his Father\'s business. <strong>dei</strong> — must, it is necessary — the divine necessity (<em>dei</em>) that governs Jesus\'s mission throughout Luke (4:43; 9:22; 13:33; 17:25; 24:7) appears here at its first speaking: his entire life is shaped by this necessity.</p>',
    "50": '<p><strong>kai autoi ou sunēkan to rēma</strong> — and they did not understand the word — their failure to understand (<em>ou sunēkan</em>, from <em>suniēmi</em> — to understand, put together) establishes a pattern that runs throughout Luke: those closest to Jesus repeatedly fail to grasp the meaning of his words, especially those concerning the <em>dei</em> of his mission. Understanding comes only after the resurrection (24:45).</p>',
    "51": '<p><strong>kai katebē met autōn kai ēlthen eis Nazareth kai ēn hypotassomenos autois</strong> — he went down with them and came to Nazareth and was subject/submitting to them — <em>hypotassō</em> (subject, subordinate, arrange under) in the present participle (<em>hypotassomenos</em>) describes an ongoing, voluntary self-subordination of the twelve-year-old who has just spoken of divine necessity. The one who must be in his Father\'s affairs voluntarily places himself under parental authority — the same paradox of the incarnation that Phil 2:6-8 articulates theologically. <em>Hē de mētēr autou dietērei panta ta rēmata tauta en tē kardia autēs</em> — his mother treasured all these things in her heart — the second Mary-treasuring notice (cf. 2:19), bookending the temple episode.</p>',
    "52": '<p><strong>Iēsous proekopten en tē sophia kai hēlikia kai chariti para theō kai anthrōpois</strong> — Jesus advanced in wisdom and stature and favor with God and men — <em>prokoptō</em> (advance, make progress, cut a path forward) is an imperfect indicating gradual development over time. The fourfold description — wisdom (<em>sophia</em>), age/stature (<em>hēlikia</em>), grace with God (<em>charis para theō</em>), grace with people (<em>charis para anthrōpois</em>) — is modeled on 1 Sam 2:26 (Samuel grew in favor with both God and men). Luke presents Jesus\'s development as a genuine human growth process, consistent with the incarnation; the one who had divine wisdom grew in its human expression.</p>'
  },
  "3": {
    "1": '<p><strong>en etei de pentekaidekaton tēs hēgemonian Tiberiou Kaisaros</strong> — in the fifteenth year of the reign of Tiberius Caesar — Luke\'s synchronistic dating, using six concurrent rulers, is the most elaborate historical synchronism in the NT and follows Thucydidean historiographical method. The fifteenth year of Tiberius (who began sole reign in 14 CE) places John\'s ministry at approximately 28-29 CE. The list: Tiberius (emperor), Pilate (prefect of Judea), Herod Antipas (tetrarch of Galilee), Philip (tetrarch of Ituraea-Trachonitis), Lysanias (tetrarch of Abilene), Annas and Caiaphas (high priests). The two high priests reflect the political reality that Rome had replaced the Hasmonean-era single high priest with appointees.</p>',
    "2": '<p><strong>egeneto rēma theou epi Iōannēn</strong> — the word of God came upon John — <em>ginomai rēma theou epi</em> is the standard LXX formula for prophetic commissioning (cf. Jer 1:1-2; Ezek 1:3; Hos 1:1; Joel 1:1; Mic 1:1); Luke presents John\'s calling as formally equivalent to the classical OT prophets. <em>En tē erēmō</em> (in the wilderness) is the prophetic staging location — John is commissioned in the wilderness, the same space as Moses at the burning bush and Elijah at Horeb.</p>',
    "3": '<p><strong>baptisma metanoias eis aphesin hamartiōn</strong> — a baptism of repentance for the forgiveness of sins — the phrase is dense: <em>baptisma</em> (a dipping, submersion — not merely sprinkling); <em>metanoia</em> (change of mind/orientation, turning — from <em>meta</em> = after/change + <em>nous</em> = mind; in LXX it translates <em>shuv</em>, the covenantal turning-back to God); <em>eis aphesin hamartiōn</em> (for/unto the release/forgiveness of sins — <em>aphesis</em> from <em>aphiēmi</em> = to release, let go, forgive). The preposition <em>eis</em> is hotly debated: it can indicate purpose (for the purpose of forgiveness) or result (resulting in forgiveness), affecting whether the baptism is a sign of a prior repentance or an instrument of forgiveness.</p>',
    "4": '<p><strong>phōnē boōntos en tē erēmō</strong> — a voice of one crying in the wilderness — the LXX text of Isa 40:3 that Luke quotes positions the comma differently from the MT: "a voice of one crying: in the wilderness prepare the way" vs. "a voice of one crying in the wilderness: prepare the way." Luke follows the LXX, connecting the voice to the wilderness (John is in the wilderness, v.2) rather than the way. <em>Ktl</em>: Luke\'s Isaiah citation (40:3-5) is the longest of the Synoptic quotations of this passage, extending to "all flesh will see the salvation of God" — the Gentile-inclusive conclusion that Matthew and Mark omit.</p>',
    "5": '<p><strong>pasa pharagx plērōthēsetai kai pan oros kai bounos tapeinōthēsetai</strong> — every valley will be filled, every mountain and hill brought low — the quotation continues Isa 40:4-5 in LXX form; Luke extends the citation to include the universalist conclusion. The road-building imagery (<em>eutheias</em> = straight, <em>tracheias</em> = rough) is Isaiah\'s metaphor for divine preparation of the way for the returning glory of YHWH. The straightening and leveling is both literal (road construction for royal processions) and metaphorical (the removal of obstacles to divine visitation).</p>',
    "6": '<p><strong>kai opsetai pasa sarx to sōtērion tou theou</strong> — and all flesh will see the salvation of God — <em>pasa sarx</em> (all flesh) is the universalist formula for humanity without ethnic distinction; <em>sōtērion</em> (salvation, noun form) rather than <em>sōtēria</em> is Luke\'s preferred form (also 2:30; Acts 28:28). Luke\'s extension of the Isaiah citation to this verse is programmatic: his Gospel and Acts will trace the fulfillment of the "all flesh" scope of salvation. The salvation is to be <em>seen</em> (<em>opsetai</em>) — Luke\'s emphasis on witnesses who see is characteristic (1:2; Acts 1:8).</p>',
    "7": '<p><strong>genēmata echidnōn</strong> — offspring/brood of vipers — the noun <em>genēmata</em> (things born, brood) from <em>ginomai</em> rather than <em>gennēmata</em> from <em>gennaō</em> (to beget); the distinction is between "what has been born" and "what has been begotten." Some manuscripts have <em>gennēmata</em> (cf. Matt 3:7). <em>Echidna</em> (viper) is one of the most venomous snakes in the Levant; the address "offspring of vipers" carries the resonance of the serpent of Gen 3 — John is accusing the crowd of being offspring of the ancient adversary. <em>Tis hypedeicen hymin phugein</em> — who warned you to flee — <em>hypodeiknymi</em> (show under, warn) is used of prophetic or divine warning (cf. Acts 9:16; 20:35).</p>',
    "8": '<p><strong>poiēsate oun karpous axious tēs metanoias</strong> — therefore produce fruits worthy of repentance — the agricultural metaphor of fruit as evidence of genuine inner change is standard in prophetic rhetoric (Isa 5:1-7; Jer 17:8). The command is plural (<em>poiēsate</em> — all of you, collectively) addressed to the crowd. <strong>mē arxēsthe legein en heautois</strong> — do not begin to say to yourselves — <em>archomai</em> with the infinitive is a Lukan idiom for beginning an action; the warning not to begin a thought implies that this rationalizing has already started. <strong>ek tōn lithōn toutōn</strong> — from these stones — the possible Aramaic wordplay (<em>avanim</em>/stones = <em>banim</em>/sons) works in Aramaic but not Greek, suggesting an underlying Aramaic tradition.</p>',
    "9": '<p><strong>ēdē de kai hē axinē pros tēn rhizan tōn dendrōn keitai</strong> — even now the axe is laid to the root of the trees — <em>ēdē</em> (even now, already) creates urgency; the axe is not yet swinging but is positioned. <em>Axinē</em> (axe) is the chopping implement for felling trees, used as a judgment metaphor throughout the prophets (Isa 10:15; Jer 46:22). The fruit/root/axe metaphor is coherent: trees that produce no fruit have their root-existence threatened. <em>Pan de dendron mē poioun karpon kalon</em> — every tree not bearing good fruit — the singular universal (<em>pan... mē</em>) addresses each hearer individually.</p>',
    "10": '<p><strong>kai epērōtōn auton hoi ochloi</strong> — the crowds were asking him — <em>epērōtaō</em> (ask, question) combined with the imperfect (<em>epērōtōn</em>) suggests repeated or ongoing questioning — the crowd continues to ask. The three-group structure (crowd, tax collectors, soldiers) gives John\'s ethical instruction a social breadth that covers the economic (sharing), the systemic (tax justice), and the coercive (military/police power) dimensions of the community\'s life.</p>',
    "11": '<p><strong>ho echōn duo chitōnas metadotō tō mē echonti</strong> — the one who has two tunics, let him share with the one who has none — <em>chitōn</em> (inner garment, tunic) is the basic garment worn under the outer <em>himation</em>; to have two was modest prosperity, to have none was poverty. <em>Metadidōmi</em> (share, give a portion from one\'s own) is Luke\'s verb for practical generosity (Rom 1:11; Eph 4:28). The food instruction (<em>brōmata</em> = food) follows the same pattern: share from what you have. John\'s ethical teaching is not revolutionary redistribution but basic covenant solidarity.</p>',
    "12": '<p><strong>elthon de kai telōnai baptisthēnai</strong> — tax collectors also came to be baptized — <em>telōnēs</em> (tax collector) describes those who bid for the right to collect imperial taxes in a region and were despised as collaborators with Rome and as systemically dishonest. Their coming for baptism signals that John\'s call includes those outside the social-religious mainstream. <em>Didaskalos, ti poiēsōmen</em> — teacher, what shall we do — the honorific <em>didaskalos</em> (teacher) from the tax collectors signals their genuine inquiry.</p>',
    "13": '<p><strong>mēden pleon para to diatetagmenon hymin prassete</strong> — collect nothing more than what you have been authorized — <em>diatetagmenon</em> (ordered, authorized — perfect passive participle of <em>diatassō</em>) refers to the officially sanctioned collection rate. Tax collectors regularly charged above the official rate and pocketed the difference; John commands ethical compliance with the legal framework. He does not condemn the profession but its abuse — a notable moderation compared to the revolutionary expectations he might have encouraged.</p>',
    "14": '<p><strong>mēdena diaseiēte mēde sykophantēsēte</strong> — do not intimidate anyone or extort falsely — <em>diaseiō</em> (shake thoroughly, intimidate) is specifically the extortion by force or threat; <em>sykophantēsēte</em> (from <em>sykophantēs</em>) denotes false accusation for personal gain, extortion by false charges. The soldiers\' ethics (<em>strateuomenoi</em> = serving as soldiers, possibly including police/enforcement roles) are addressed with the same concrete specificity as the tax collectors. <em>Arkeisthe tois opsōniois hymin</em> — be content with your wages — <em>opsōnion</em> (soldier\'s pay, rations) is military pay vocabulary.</p>',
    "15": '<p><strong>prosdokōntos de tou laou kai dialogizomenōn pantōn en tais kardiais autōn peri tou Iōannou</strong> — while the people were in expectation, all reasoning in their hearts about John — <em>prosdokaō</em> (expect, await) describes the messianic anticipation that John\'s ministry had awakened; the people were wondering whether he himself was the Christ. <em>Dialogizomai en kardiais</em> (reason in hearts) is Luke\'s phrase for the interior deliberation that is not yet spoken aloud (cf. 1:29; 5:22; 12:17).</p>',
    "16": '<p><strong>baptizō hymas hydati, erchetai de ho ischuroteros mou</strong> — I baptize you with water, but one who is mightier than I is coming — the contrast is water/<em>pneumati hagiō kai puri</em> (Holy Spirit and fire). The single preposition <em>en</em> governing both <em>pneumati hagiō</em> and <em>puri</em> (Holy Spirit and fire) suggests these are one unified baptism rather than two separate ones — the Spirit-fire baptism is the single eschatological event. <em>Ou ouk eimi hikanos lysai ton himanta tōn hypodēmatōn autou</em> — whose sandal strap I am not worthy to untie — the untying of sandals was the task of the lowest slave; John places himself below even slave rank relative to the Coming One.</p>',
    "17": '<p><strong>hou to ptuon en tē cheiri autou</strong> — whose winnowing fork is in his hand — <em>ptuon</em> (winnowing fork, shovel) is the flat wooden implement used to toss threshed grain into the wind so the lighter chaff is blown away and the heavier grain falls back. The threshing floor (<em>alōn</em>) metaphor is a standard prophetic judgment image (Isa 41:16; Jer 15:7; Mic 4:12). <em>Achuron</em> (chaff) vs. <em>siton</em> (wheat/grain) — the separation of chaff and grain is the judgment that the Coming One will execute. <em>Puri asbstō</em> — unquenchable fire — the eschatological fire of judgment.</p>',
    "18": '<p><strong>polla men oun kai hetera parakalōn euēngelizeto ton laon</strong> — with many other exhortations he was preaching good news to the people — <em>parakalōn</em> (exhorting, encouraging — present participle of <em>parakaleō</em>) is one of Luke\'s favorite verbs for the proclamation that calls to action. <em>Euēngelizeto</em> (imperfect of <em>euangelizō</em>) — Luke\'s distinctive proclamation-verb characterizes even John\'s preaching as "good news" proclamation, though the content is primarily repentance and warning rather than kingdom arrival.</p>',
    "19": '<p><strong>ho de Hērōdēs ho tetrarchēs</strong> — Herod the tetrarch — Luke introduces John\'s imprisonment prolepticly (before the baptism narrative is complete) to clear the Herodian complication from the narrative. <em>Elenkhomenos hyp autou</em> (being reproved by him) — the participle of <em>elenchō</em> (reprove, expose) describes John\'s confrontation of Herod over Herodias (his brother Philip\'s wife, Lev 18:16) and his other crimes (<em>ponēria</em>).</p>',
    "20": '<p><strong>prosēthēken kai touto epi pasin</strong> — he added this also to all of them — the phrase frames Herod\'s imprisonment of John as the culmination of a series of <em>ponērias</em> (evil deeds) that Luke summarizes without detailing. The proleptic imprisonment notice removes Herod from the baptism scene — Luke will not have Herod present at the baptism as Matthew and Mark do not either.</p>',
    "21": '<p><strong>en tō baptisthēnai hapanta ton laon kai Iēsou baptisthentos kai proseuchomenou</strong> — when all the people were being baptized and when Jesus was baptized and was praying — three notable Lukan features: (1) Jesus\'s baptism is subordinated grammatically (<em>Iēsou baptisthentos</em> — aorist passive participle, genitive absolute, not the main verb); (2) the main verb is <em>proseuchomenou</em> (while praying — present participle); (3) the heavens open specifically in response to prayer. Luke\'s prayer emphasis places the baptism-theophany within Jesus\'s prayer life — the revelation comes while he prays.</p>',
    "22": '<p><strong>sōmatikō eidei</strong> — in bodily form — Luke\'s unique addition to the baptism account; <em>sōmatikos</em> (bodily, physical) ensures the dove\'s manifestation is visible and corporeal, not merely visionary. This guards against a docetic interpretation and emphasizes the reality of the Spirit\'s descent. The dove (<em>peristera</em>) as the Spirit\'s visible form is universally attested in the Synoptic tradition; the symbolism connects to Gen 1:2 (Spirit hovering), Ps 74:19 (turtle-dove of affliction), and the Noah dove (Gen 8:8-12).</p>',
    "23": '<p><strong>hōsei etōn triakonta archomenos</strong> — about thirty years old when he began — <em>hōsei</em> (about, approximately) is Luke\'s qualification that this is not a precise number; thirty was the traditional age of priestly service (Num 4:3) and of Davidic kingship (2 Sam 5:4). <em>Archomenos</em> (beginning — present participle, perhaps nominative absolute) signals the inception of the public ministry. <em>Hōs enomizeto</em> (as was supposed/thought) — the passive of <em>nomizō</em> (think customary, suppose) signals that what follows is the legal genealogy, not the biological one.</p>',
    "24": '<p>Luke\'s genealogy runs from Jesus back to Adam in ascending order (unlike Matthew\'s descending from Abraham), which serves Luke\'s universal theological purpose: he is tracing humanity\'s origin, not merely Israel\'s Davidic line. The names between Joseph and Zerubbabel differ significantly from Matthew\'s list, which has generated extensive discussion; the most likely explanation is that Luke records Mary\'s biological line (through Heli = Mary\'s father) while Matthew records Joseph\'s legal Davidic line — the genealogy is Joseph\'s in both cases legally, but Luke\'s biological connections may trace Mary\'s ancestry through different branches.</p>',
    "25": '<p>Luke\'s genealogy from Mattathias through Cosam and Addi covers the post-exilic period with names not found in the OT or Matthew, suggesting access to tribal/family records preserved into the Second Temple period. The genealogical precision — with 77 names from Adam to Jesus (symbolic of completeness, 7×11) — indicates that Luke is presenting a carefully structured theological genealogy, not merely a historical list.</p>',
    "26": '<p>The name sequence through Maath, Mattathias, and Semein in Luke\'s genealogy is part of the post-exilic segment that diverges from Matthew. Luke\'s genealogy through Nathan (son of David, v.31) rather than Solomon (Matthew\'s line) may reflect the use of 2 Sam 5:14 / 1 Chr 3:5; Zechariah\'s prophecy that the house of Nathan would mourn (Zech 12:12) is sometimes cited as relevant to the messianic line.</p>',
    "27": '<p>Luke\'s genealogy passes through Zerubbabel (the Davidic governor who led the return from exile) and Shealtiel — names also in Matthew\'s genealogy at this point — before diverging again. The convergence at Zerubbabel/Shealtiel is the one consistent point where the two genealogies agree after David; from here both traditions required connection to the Davidic line through the post-exilic community.</p>',
    "28": '<p>Luke\'s genealogy continues its careful enumeration through the Davidic line; the names in this portion (Cosam, Addi, Melchi, etc.) are not cross-referrable to OT records, which is consistent with post-exilic family records that were maintained within priestly and royal families for purposes of covenant inheritance claims.</p>',
    "29": '<p>The continuation through Elmadam, Er, and Joshua in Luke\'s genealogy maintains the careful tracing of the Davidic line. Luke\'s genealogy contains 77 names from Adam to Jesus — a number that is likely deliberate (seven sets of eleven, or seven being the number of completeness), reflecting Luke\'s theological shaping of the historical material he received.</p>',
    "30": '<p>Luke\'s genealogy through Simeon, Levi, and Matthat covers the pre-exilic portion with additional Davidic line names. The presence of Levi and Simeon as ancestors of Jesus (not the patriarchs but later figures) is consistent with the common practice of naming children after famous ancestors; multiple generations might share the same names, creating the appearance of conflation with earlier figures.</p>',
    "31": '<p><strong>tou Nathan tou Dauid</strong> — son of Nathan, son of David — Luke\'s genealogy traces the Davidic descent through Nathan (2 Sam 5:14; 1 Chr 3:5) rather than Solomon (Matthew\'s line). Both Nathan and Solomon were sons of David by Bathsheba; the divergence at this point explains the different name lists in the two genealogies. Zechariah 12:12 mentions the "house of Nathan" separately, and this Nathan-branch was a recognized alternative Davidic line.</p>',
    "32": '<p><strong>tou Iessai tou Iōbēd tou Boos</strong> — son of Jesse, son of Obed, son of Boaz — this section of Luke\'s genealogy converges with Matthew\'s (and with Ruth 4:17-22): Jesse-Obed-Boaz-Salmon. Both genealogies must pass through the same pre-Davidic figures; the differences between Matthew and Luke are concentrated in the post-Davidic and post-exilic periods. Boaz and Ruth\'s union (the Moabitess) is the Gentile inclusion precedent in the Davidic ancestry.</p>',
    "33": '<p><strong>tou Aminadab tou Admin tou Arni</strong> — Luke\'s genealogy includes Arni (not in Matthew) between Hezron and Aminadab; Matthew has Ram (= Arni in Greek transliteration of the same Hebrew name) directly. The slight variations in transliteration of Hebrew names between Matthew and Luke reflect independent Greek translations of the same Aramaic/Hebrew sources.</p>',
    "34": '<p><strong>tou Iakōb tou Isaak tou Abraam</strong> — son of Jacob, son of Isaac, son of Abraham — Luke reaches the patriarchs at this point; from here to Adam the genealogy follows the LXX Septuagint genealogies (Gen 5; 11). Matthew stops at Abraham; Luke continues to Adam and God, serving his universal theological purpose. The three patriarchs are the covenant foundation — the promises to Abraham, confirmed through Isaac and Jacob, now reach their fulfillment in Jesus.</p>',
    "35": '<p>Luke\'s genealogy continues through the pre-Abrahamic patriarchs in descending order: Peleg, Reu, Serug, Nahor, Terah — the Table of Nations and primeval genealogy of Gen 11:10-26. Luke follows the LXX enumeration, which adds Cainan (son of Arphaxad) in v.36 — a name present in the LXX of Gen 11:12-13 but absent from the MT.</p>',
    "36": '<p><strong>tou Kainam tou Arphaxad</strong> — son of Cainan, son of Arphaxad — the Cainan between Shem and Arphaxad is present in the LXX of Gen 11:12-13 and Luke\'s genealogy follows this reading. The MT lacks Cainan here; the LXX addition (possibly from Gen 10:24) creates a textual difference between the Hebrew and Greek OT. Luke\'s use of the LXX Cainan is consistent with his broader dependence on the LXX for OT citations throughout Luke-Acts.</p>',
    "37": '<p>Luke\'s genealogy continues through the ante-diluvian patriarchs: Methuselah, Enoch, Jared, Mahalaleel, Cainan — following Gen 5 in LXX order. <strong>Enoch</strong> is particularly significant: Gen 5:24 notes that "Enoch walked with God and was no more, because God took him away" — a cryptic reference to translation without death that generated extensive Second Temple literature (1 Enoch, 2 Enoch). The presence of Enoch in the lineage of Jesus connects the eschatological traditions of Enoch\'s translation to the ultimate eschatological figure.</p>',
    "38": '<p><strong>tou Sēth tou Adam tou theou</strong> — son of Seth, son of Adam, son of God — Luke\'s genealogy ends where it began, with the divine: the <em>son of Adam, son of God</em> that closes the genealogy frames Jesus as the completion of what Adam began. Adam was the son of God by creation; Jesus is the Son of God by eternal generation and incarnation. Where Adam failed the sonship (the temptation narrative immediately follows in 4:1-13), Jesus will succeed. The genealogy that began with "son of God" (in the baptism voice, 3:22) ends with "son of God" (the first man\'s relationship to his Creator) — the inclusio structures Luke\'s understanding of what the incarnation accomplishes: the restoration of humanity\'s original relationship to God, realized in the Son who is both the Father\'s eternal Son and Adam\'s descendant.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'luke')
    merge_comm(existing, LUKE_CH2_3)
    save_comm('mkt-original', 'luke', existing)
    ch2 = len(existing.get('2', {}))
    ch3 = len(existing.get('3', {}))
    print(f'Luke 2: {ch2} verses, Luke 3: {ch3} verses.')

if __name__ == '__main__':
    main()
